sql:
SELECT AVG(score) AS average_score, COUNT(attempt_id) AS total_attempts
FROM student_quiz_attempts
WHERE quiz_id = 1;

SELECT AVG(score) AS average_score, MAX(score) AS max_score, COUNT(*) AS total_attempts
FROM student_quiz_attempts
WHERE quiz_id = 1;

SELECT quiz_id, AVG(score) AS average_score
FROM student_quiz_attempts
GROUP BY quiz_id;

SELECT quiz_title, total_marks, COUNT(*) AS number_of_quizzes
FROM quizzes
GROUP BY quiz_title;

external_knowledge:
; Average score refers to the mean percentage score of all students for a given difficulty level; 
; Pass rate refers to the proportion of students who passed the quiz for a given difficulty level; 
; Total attempts refer to the total number of attempts made by students for a given difficulty level; 
; Difficulty levels are ordered from highest to lowest average score, indicating the most challenging levels first.

Permitting feedback refers to quizzes where the "allow_feedback" field is set to 1; 
Multiple students refer to more than one distinct "student_id"; 
Average score is the mean score achieved by all students who have attempted a particular quiz.
